document.addEventListener("DOMContentLoaded",function(){console.log("[FORM UNIFICADO V5] Script carregado e DOM pronto.");const form=document.getElementById("unified-form");const redirectionModal=document.getElementById("redirection-modal");const closeModalButton=document.querySelector(".close-modal-button");const continueToPaymentButton=document.getElementById("continue-to-payment");if(!form){console.error("[ERRO FORM UNIFICADO V5] Formulário #unified-form não encontrado.");return}if(!redirectionModal||!closeModalButton||!continueToPaymentButton){console.error("[ERRO FORM UNIFICADO V5] Elementos do modal não encontrados.")}const nomeInput=document.getElementById("nome-completo");const whatsappInput=document.getElementById("whatsapp");const modalidadeSelect=document.getElementById("modalidade");const planoSelect=document.getElementById("plano");const periodicidadeSelect=document.getElementById("periodicidade");const treinadorSelect=document.getElementById("treinador");const termosCheckbox=document.getElementById("termos");if(!nomeInput||!whatsappInput||!modalidadeSelect||!planoSelect||!periodicidadeSelect||!treinadorSelect||!termosCheckbox){console.error("[ERRO FORM UNIFICADO V5] Um ou mais elementos essenciais do formulário não foram encontrados. Verifique os IDs no HTML.");return}console.log("[FORM UNIFICADO V5] Todos os elementos do formulário foram encontrados.");let currentCheckoutUrl="#";let treinadorUrlParam=null;function obterParametroUrl(nome){const urlParams=new URLSearchParams(window.location.search);return urlParams.get(nome)}const modalidadeUrl=obterParametroUrl("modalidade");const planoUrl=obterParametroUrl("plano");const periodicidadeUrl=obterParametroUrl("periodicidade");treinadorUrlParam=obterParametroUrl("treinador");if(treinadorUrlParam){console.log(`[FORM UNIFICADO V5] Treinador na URL: ${treinadorUrlParam}`)}if(modalidadeUrl){modalidadeSelect.value=modalidadeUrl;console.log(`[FORM UNIFICADO V5] Modalidade pré-selecionada pela URL: ${modalidadeUrl}`)}if(planoUrl){planoSelect.value=planoUrl;console.log(`[FORM UNIFICADO V5] Plano pré-selecionado pela URL: ${planoUrl}`)}if(periodicidadeUrl){periodicidadeSelect.value=periodicidadeUrl;console.log(`[FORM UNIFICADO V5] Periodicidade pré-selecionada pela URL: ${periodicidadeUrl}`)}const regiaoUrl=obterParametroUrl("regiao");console.log(`[FORM UNIFICADO V5] Região detectada: ${regiaoUrl}`);const treinadoresPorRegiao={florianopolis:{corrida:{essencial:["Bruno Jeremias","Thais Prando"],premium:["Bruno Jeremias","Thais Prando","Elinai Freitas"]},triathlon:{essencial:["Thais Prando"],premium:["Thais Prando","Elinai Freitas"]}},"sao-paulo":{corrida:{essencial:["Denis Santana","Jéssica Rodrigues"],premium:["Denis Santana","Jéssica Rodrigues"]},triathlon:{essencial:["Denis Santana","Jéssica Rodrigues"],premium:["Denis Santana","Jéssica Rodrigues"]}},online:{corrida:{essencial:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando"],premium:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando"]},triathlon:{essencial:["Jéssica Rodrigues","Thais Prando"],premium:["Jéssica Rodrigues","Thais Prando"]}}};function obterTreinadores(modalidade,plano,regiao="florianopolis"){if(treinadoresPorRegiao[regiao]&&treinadoresPorRegiao[regiao][modalidade]){return treinadoresPorRegiao[regiao][modalidade][plano]||[]}return treinadoresPorRegiao["florianopolis"][modalidade][plano]||[]}const treinadores={corrida:{essencial:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando"],premium:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando"]},triathlon:{essencial:["Jéssica Rodrigues","Thais Prando"],premium:["Jéssica Rodrigues","Thais Prando"]}};const treinadoresSlugMap={"bruno-jeremias":"Bruno Jeremias","jessica-rodrigues":"Jéssica Rodrigues","thais-prando":"Thais Prando","elinai-freitas":"Elinai Freitas"};const tecnoFitLinks={corrida:{essencial:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MDkz",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MDk3",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTA0"},premium:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MDk1",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTAw",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTEw"}},triathlon:{essencial:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTEy",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTE2",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTE3"},premium:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTIx",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTIy",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTI1"}}};console.log("[FORM UNIFICADO V5] Links Tecnofit definidos.");function atualizarTreinadores(){treinadorSelect.innerHTML=`<option value="">Selecione o Treinador</option>`;const modalidade=modalidadeSelect.value;const plano=planoSelect.value;if(modalidade&&plano){const treinadoresDisponiveis=obterTreinadores(modalidade,plano,regiaoUrl);console.log(`[FORM UNIFICADO V5] Treinadores para ${modalidade}/${plano}/${regiaoUrl}:`,treinadoresDisponiveis);treinadoresDisponiveis.forEach(treinador=>{const option=document.createElement("option");const slug=treinador.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g,"-");option.value=slug;option.textContent=treinador;treinadorSelect.appendChild(option)});if(treinadorUrlParam){console.log(`[FORM UNIFICADO V5] Tentando selecionar treinador: ${treinadorUrlParam}`);const optionToSelect=Array.from(treinadorSelect.options).find(option=>option.value===treinadorUrlParam);if(optionToSelect){treinadorSelect.value=treinadorUrlParam;console.log(`[FORM UNIFICADO V5] Treinador selecionado: ${treinadorUrlParam}`)}else{console.warn(`[FORM UNIFICADO V5] Treinador ${treinadorUrlParam} não encontrado nas opções disponíveis para região ${regiaoUrl}.`)}}}}if(modalidadeSelect.value&&planoSelect.value){atualizarTreinadores()}modalidadeSelect.addEventListener("change",atualizarTreinadores);planoSelect.addEventListener("change",atualizarTreinadores);function showModal(){if(redirectionModal){redirectionModal.style.display="flex";setTimeout(()=>redirectionModal.classList.add("active"),10);console.log("[FORM UNIFICADO V5] Modal exibido.")}}function hideModal(){if(redirectionModal){redirectionModal.classList.remove("active");setTimeout(()=>redirectionModal.style.display="none",300);console.log("[FORM UNIFICADO V5] Modal ocultado.")}}if(closeModalButton){closeModalButton.addEventListener("click",hideModal)}if(continueToPaymentButton){continueToPaymentButton.addEventListener("click",function(){if(currentCheckoutUrl&&currentCheckoutUrl!=="#"){console.log(`[FORM UNIFICADO V5] Botão 'Continuar' clicado. Enviando evento de conversão e redirecionando para: ${currentCheckoutUrl}`);if(typeof gtagSendEvent==="function"){gtagSendEvent(currentCheckoutUrl)}else{console.warn("[FORM UNIFICADO V5] Função gtagSendEvent não encontrada, redirecionando diretamente.");window.location.href=currentCheckoutUrl}}hideModal()})}if(redirectionModal){redirectionModal.addEventListener("click",function(event){if(event.target===redirectionModal){hideModal()}})}form.addEventListener("submit",function(event){event.preventDefault();event.stopPropagation();console.log("[FORM UNIFICADO V5] Evento de submit disparado e prevenido.");if(!nomeInput.value.trim()){alert("Por favor, preencha o nome completo.");return false}if(!whatsappInput.value.trim()){alert("Por favor, preencha o WhatsApp.");return false}if(!modalidadeSelect.value){alert("Por favor, selecione uma modalidade.");return false}if(!planoSelect.value){alert("Por favor, selecione um plano.");return false}if(!periodicidadeSelect.value){alert("Por favor, selecione uma periodicidade.");return false}if(!treinadorSelect.value){alert("Por favor, selecione um treinador.");return false}if(!termosCheckbox.checked){alert("Por favor, aceite os termos de contrato.");return false}console.log("[FORM UNIFICADO V5] Validações passaram.");const modalidade=modalidadeSelect.value;const plano=planoSelect.value;const periodicidade=periodicidadeSelect.value;if(tecnoFitLinks[modalidade]&&tecnoFitLinks[modalidade][plano]&&tecnoFitLinks[modalidade][plano][periodicidade]){currentCheckoutUrl=tecnoFitLinks[modalidade][plano][periodicidade];console.log(`[FORM UNIFICADO V5] URL Tecnofit encontrada e armazenada: ${currentCheckoutUrl}`)}else{console.error(`[ERRO FORM UNIFICADO V5] URL Tecnofit NÃO encontrada para: Modalidade='${modalidade}', Plano='${plano}', Periodicidade='${periodicidade}'.`);alert("Erro: Link de checkout não encontrado. Verifique as seleções ou contate o suporte.");currentCheckoutUrl="#";return false}const dadosCadastro={nome:nomeInput.value,whatsapp:whatsappInput.value,modalidade:modalidadeSelect.options[modalidadeSelect.selectedIndex].text,plano:planoSelect.options[planoSelect.selectedIndex].text,periodicidade:periodicidadeSelect.options[periodicidadeSelect.selectedIndex].text,treinador:treinadorSelect.options[treinadorSelect.selectedIndex].text,urlTecnofit:currentCheckoutUrl};localStorage.setItem("dadosCadastro",JSON.stringify(dadosCadastro));console.log("[FORM UNIFICADO V5] Dados salvos no localStorage.");const formData=new FormData;formData.append("nome_completo",nomeInput.value);formData.append("whatsapp",whatsappInput.value);formData.append("modalidade",modalidadeSelect.options[modalidadeSelect.selectedIndex].text);formData.append("plano",planoSelect.options[planoSelect.selectedIndex].text);formData.append("periodicidade",periodicidadeSelect.options[periodicidadeSelect.selectedIndex].text);formData.append("treinador",treinadorSelect.options[treinadorSelect.selectedIndex].text);formData.append("termos","aceito");console.log("[FORM UNIFICADO V5] Enviando dados para Formspree...");fetch("https://formspree.io/f/xovdwrjz",{method:"POST",body:formData,headers:{Accept:"application/json"}}).then(response=>{console.log("[FORM UNIFICADO V5] Resposta do Formspree:",response.status);window.location.href="obrigado.html"}).catch(error=>{console.error("[FORM UNIFICADO V5] Erro ao enviar para Formspree:",error);window.location.href="obrigado.html"});return false});console.log("[FORM UNIFICADO V5] Script totalmente inicializado.")});